    }

    [Test, Order(8)]
    public async Task UpdateOrder_ExistingId_Returns200()
    {
        var created = await CreateTestOrder();
        var updateRequest = new OrderRequest
        {
            CustomerId = _customerId,
            EmployeeId = _employeeId,
            StatusId = 2, // Invoiced
            OrderDate = DateTime.UtcNow
        };
        var response = await _client.PutAsJsonAsync($"/api/orders/{created.OrderId}", updateRequest);
        Assert.That(response.StatusCode, Is.EqualTo(HttpStatusCode.OK));
        var updated = await response.Content.ReadFromJsonAsync<OrderSummaryDto>();
        Assert.That(updated!.StatusId, Is.EqualTo(2));
        Assert.That(updated.ModifiedOn, Is.Not.Null);
