        Assert.That(response.StatusCode, Is.EqualTo(HttpStatusCode.NotFound));
    }

    [Test, Order(10)]
    public async Task DeleteOrder_ExistingId_Returns204()
    {
        var created = await CreateTestOrder();
        var response = await _client.DeleteAsync($"/api/orders/{created.OrderId}");
        Assert.That(response.StatusCode, Is.EqualTo(HttpStatusCode.NoContent));
        // Verify deleted
        var getResp = await _client.GetAsync($"/api/orders/{created.OrderId}");
        Assert.That(getResp.StatusCode, Is.EqualTo(HttpStatusCode.NotFound));
