    [Test, Order(11)]
    public async Task DeleteOrder_NonExistentId_Returns404()
    {
        var response = await _client.DeleteAsync("/api/orders/99999");
        Assert.That(response.StatusCode, Is.EqualTo(HttpStatusCode.NotFound));
    }

    private async Task<OrderSummaryDto> CreateTestOrder()
    {
        var request = new OrderRequest
        {
            CustomerId = _customerId,
            EmployeeId = _employeeId,
            StatusId = 3,
            OrderDate = DateTime.UtcNow
        };
        var response = await _client.PostAsJsonAsync("/api/orders", request);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<OrderSummaryDto>())!;
    }
